<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';
require_once dirname(__DIR__,3).'/includes/academico_flujo.php';
exigirPermiso('academic.supervise');if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}if(!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit('Solicitud inválida.');}$id=cmsId($_POST['inscripcion_id']??0);
try{if(!$id)throw new DomainException('Inscripción inválida.');$pdo=obtenerConexion();$p=progresoInscripcion($pdo,$id);if(!$p['elegible'])throw new DomainException('El estudiante todavía tiene requisitos obligatorios pendientes o rechazados.');$cert=generarCertificadoInscripcion($pdo,$id,(int)$_SESSION['usuario_id']);$pdo->prepare('UPDATE inscripciones_capacitacion SET finalizacion_confirmada_por=:u,finalizacion_confirmada_at=COALESCE(finalizacion_confirmada_at,NOW()) WHERE id=:i')->execute(['u'=>(int)$_SESSION['usuario_id'],'i'=>$id]);registrarAuditoria(['event_type'=>'academic.certificate_issued','module'=>'academico','entity_type'=>'inscripcion','entity_id'=>$id,'action'=>'issue','description'=>'Administrador confirmó la finalización y emitió el certificado.','metadata'=>['certificado_id'=>$cert['id']]],$pdo);cmsFlash('success','Finalización confirmada y certificado emitido.');}catch(Throwable $e){cmsFlash('danger',$e instanceof DomainException?$e->getMessage():'No fue posible emitir el certificado.');}header('Location: '.atenea_url('src/dashboard/academico/seguimiento.php'));exit;
